var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"코핀 오브 아스모데우스… 최초 가동일로부터 ■■■일 경과.","JPN":"コフィン・オブ・アスモデウス……初稼働から■■■日経過。","ENG":"Coffin of Asmodeus... ■■■ days passed since initial operation.","TWN":"阿斯蒙蒂斯之棺……自最初啟動日算起 ■■■天後。","SCN":"阿斯蒙蒂斯之棺……自最初启动之日起■■■天后。","DEU":"Coffin of Asmodeus... ■■■ days passed since initial operation.","FRA":"Coffin of Asmodeus... ■■■ days passed since initial operation."},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"균열의 침식파 유출량 및 클리파 오염 농도 점진적으로 상승 중-","JPN":"亀裂の侵食波流出量およびクリファ汚染濃度、徐々に上昇中……","ENG":"Corruption rays from the crevice and Qlipha contamination density gradually increasing.","TWN":"裂隙中流出的侵蝕波濃度及逆卡巴拉污染度逐漸上升中——","SCN":"裂隙中流出的侵蚀波浓度及逆卡巴拉污染度逐渐上升中——","DEU":"Corruption rays from the crevice and Qlipha contamination density gradually increasing.","FRA":"Corruption rays from the crevice and Qlipha contamination density gradually increasing."},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"임계치까지 남은 예상 시간… 472시간.","JPN":"臨界値までの予想残り時間……472時間。","ENG":"Estimated time until critical point... 472 hours.","TWN":"距離達到臨界點剩餘……472小時。","SCN":"预计到达临界点剩余……472小时。","DEU":"Estimated time until critical point... 472 hours.","FRA":"Estimated time until critical point... 472 hours."},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"하늘이 참 붉네요.","JPN":"空が真っ赤ですね。","ENG":"The sky bleeds crimson.","TWN":"天空真紅啊。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"마치 세상의 마지막 날처럼 불타는 것 같아요.","JPN":"まるで世界最後の日のように燃えているようであります。","ENG":"It's as if it knows the end is about to unfold.","TWN":"就像世界末日一樣燃燒著。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AURA_ADMIN_NULL_HELMET","text":{"KOREA":"우리가 늘 보아왔던 평범한 석양이다.","JPN":"私たちがいつも見てきた普通の夕暮れだ。","ENG":"It is the same ordinary sunset we've always seen.","TWN":"這就是我們一直看到的普通夕陽……"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AURA_ADMIN_NULL_HELMET","text":{"KOREA":"하지만, 저 붉은 빛이 우리의 적수를 떠올리게 한다는 건 부정할 수 없군.","JPN":"だが、あの赤い光が私たちの敵を思い出させるのは否定できないな。","ENG":"But I can't deny that the red hue reminds me of our enemy.","TWN":"但是那個紅光……確實會讓人想起我們現在的對手。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"그 마왕의 이명… 잿더미의 여왕이라고 했던가요.","JPN":"あの魔王の異名……灰の女王といいましたか？","ENG":"That Demon Lord's alias... wasn't it the Queen of Ashes?","TWN":"那個魔王的別名……好像有人把她叫作灰燼女王吧？"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"삼대국이 연합하여 결성한 북부 전선을 고작 이틀만에 무너트렸다죠.","JPN":"三大国が連合して結成した北部戦線をたった2日で滅ぼしたとか。","ENG":"They say that even the northern front formed by the three great powers fell in just two days.","TWN":"聽說三個大國聯合組成的北部戰線僅僅兩天就被她擊潰了。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AURA_ADMIN_NULL_HELMET","text":{"KOREA":"그래. 그 어떤 계략이나 농간도 없이 순수한 무력으로 부딪혀서 말이야.","JPN":"そうだ。なんの戦略も、企みもなく純粋に武力だけでぶつかってきたんだ。","ENG":"Yes. And it was by pure force, without any tricks or gimmicks.","TWN":"對。沒有任何陰謀詭計，只有純粹的武力對決。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AURA_ADMIN_NULL_HELMET","text":{"KOREA":"우리가 관을 가동하지 않았다면, 지금쯤 온 대륙이 잿더미 아래에 자취를 감췄겠지.","JPN":"私たちが棺を稼働していなかったら、今頃全大陸が灰の下に消えていただろう。","ENG":"If we didn't activate the Coffin, the whole continent would be buried in ashes by now.","TWN":"如果我們沒有啟動棺材，現在整片大陸早已化為灰燼了。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"하지만 아무것도 해결된 건 없어요. 관은 시간을 벌기 위한 임시방편일 뿐이잖아요.","JPN":"ですが、解決されたことは何もありません。棺はただの時間稼ぎにすぎないではないですか。","ENG":"But nothing has been resolved. This Coffin is just a temporary measure to buy some time.","TWN":"但什麼都沒有解決。那個棺材只是為了爭取時間的臨時措施而已。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AURA_ADMIN_NULL_HELMET","text":{"KOREA":"그거면 충분하다!","JPN":"それで十分なのだ！","ENG":"That's more than enough!","TWN":"那就足夠了!"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AURA_ADMIN_NULL_HELMET","text":{"KOREA":"덕분에 우린 무사히 대적자와 만났고, 늑대를 훌륭한 전사로 키워냈으니까!","JPN":"おかえげ私たちは無事敵対者と出会い、オオカミを立派な戦士に育て上げたではないか！","ENG":"Thanks to it, we safely met with the Antagonist and raised the Wolf into a great warrior!","TWN":"多虧如此，我們才能順利撐到與對手會面，並將狼培養成了出色的戰士！"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"당신이 아니라 힐데 씨가 가르친 거죠.","JPN":"君ではなく、ヒルデさんが育てたんでしょう。","ENG":"It was Hilde who raised the Wolf, not you.","TWN":"不是我們，培養了狼的人是希爾德。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"우리가 그 괴물을 상대로… 정말 이길 수 있을까요?","JPN":"私たちがあの化け物を相手に……本当に勝てるのでしょうか。","ENG":"Do you think we can win... against that monster?","TWN":"你真的覺得……我們真的能打贏那種怪物嗎？"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AURA_ADMIN_NULL_HELMET","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AURA_ADMIN_NULL_HELMET","text":{"KOREA":"율리아 전대장.","JPN":"ユリア戦隊長。","ENG":"Commander Yulia.","TWN":"茱莉亞隊長。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"AURA_ADMIN_NULL_HELMET","text":{"KOREA":"그대는 이 세상을 구하기 위해 무엇을 걸 수 있지?","JPN":"君はこの世界を救うために何を賭ける？","ENG":"What are you willing to risk in order to save the world?","TWN":"你能為拯救這個世界付出什麼？"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"…전부 다요.","JPN":"……すべてです。","ENG":"...Everything.","TWN":"……全部……嗎？"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"이길 수만 있다면 내 목숨이라도 바칠 거예요.","JPN":"勝てるのであれば、自分の命さえ捧げます。","ENG":"I'll give my life if it means that we can win.","TWN":"只要能贏，我願意獻出我的生命。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AURA_ADMIN_NULL_HELMET","text":{"KOREA":"좋은 각오다!","JPN":"いい覚悟だ！","ENG":"Excellent determination!","TWN":"很好的覺悟！"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AURA_ADMIN_NULL_HELMET","text":{"KOREA":"그 각오만 무너지지 않는다면 우린 이길 거다! 반드시!","JPN":"その覚悟さえ健在なら、私たちは勝つ！　必ず！","ENG":"I'm certain we'll win as long as that determination doesn't break!","TWN":"只要這種覺悟不動搖，我們就會贏！一定會贏！"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"대화를 할 때마다 그렇게 얼굴을 들이미셔야 하나요?","JPN":"話すたびにそうやって、顔を近づけないといけないんでしょうか？","ENG":"Do you always have to get all up in my face when we talk?","TWN":"我們每次說話的時候，你都有必要湊這麼近嗎？"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"흐음… 밥이나 먹으러 가죠.","JPN":"ふむ……食事でもしに行きましょうか。","ENG":"Hmm... Let's go eat something.","TWN":"哈……我們去吃點東西吧。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};